vector<vector<int>> findSubsets(vector<int>& inputNumbers) {
    int n = inputNumbers.size();
    int total = 1 << n;
    vector<vector<int>> subsets;

    for (int mask = 0; mask < total; mask++) {
        vector<int> subset;
        for (int i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                subset.push_back(inputNumbers[i]);
            }
        }
        subsets.push_back(subset);
    }

    return subsets;
}

