SubsetResult findSubsets(int *inputNumbers, int n) {
    int total = 1 << n;

    SubsetResult result;
    result.count = total;
    result.subsets = (Subset *)malloc(total * sizeof(Subset));

    for (int mask = 0; mask < total; mask++) {
        int size = 0;

        // Count elements in current subset
        for (int i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                size++;
            }
        }

        result.subsets[mask].size = size;
        result.subsets[mask].data = (int *)malloc(size * sizeof(int));

        int idx = 0;
        for (int i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                result.subsets[mask].data[idx++] = inputNumbers[i];
            }
        }
    }

    return result;
}

code.Java:
static List<List<Integer>> findSubsets(int[] inputNumbers) {
    int n = inputNumbers.length;
    int total = 1 << n;
    List<List<Integer>> result = new ArrayList<>();

    for (int mask = 0; mask < total; mask++) {
        List<Integer> subset = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) subset.add(inputNumbers[i]);
        }
        result.add(subset);
    }
    return result;
}

